//! Integration test: read a real `.binlog` file produced by `dotnet build /bl`
//! and verify that the sequential reader can parse every event without error.

use std::fs::File;

use munin::{BinaryLogRecordKind, BinlogEvent, BinlogIndex, BinlogReader};

/// Path to the test fixture generated by building a minimal .NET console app.
const HELLO_BINLOG: &str = concat!(env!("CARGO_MANIFEST_DIR"), "/tests/data/hello.binlog");

#[test]
fn read_all_events_from_real_binlog() {
    let file = File::open(HELLO_BINLOG).expect("missing test fixture: hello.binlog");
    let mut reader = BinlogReader::open(file).expect("failed to open binlog");

    // Header version must be in our supported range.
    let version = reader.header().file_format_version;
    assert!(version >= 18, "expected version >= 18, got {version}");

    let events = reader.read_all_events().expect("failed to read events");

    // A successful build of a minimal project produces at least a handful of
    // events: BuildStarted, ProjectEvaluationStarted/Finished,
    // ProjectStarted/Finished, TargetStarted/Finished, BuildFinished, etc.
    assert!(
        events.len() > 10,
        "expected more than 10 events, got {}",
        events.len()
    );

    // There must be exactly one BuildStarted event.
    let build_started_count = events
        .iter()
        .filter(|e| matches!(e, BinlogEvent::BuildStarted(_)))
        .count();
    assert_eq!(
        build_started_count, 1,
        "expected exactly 1 BuildStarted event"
    );

    // The last event must be BuildFinished.
    assert!(
        matches!(events.last().unwrap(), BinlogEvent::BuildFinished(_)),
        "last event should be BuildFinished"
    );

    // BuildFinished should indicate success.
    if let BinlogEvent::BuildFinished(ref bf) = events.last().unwrap() {
        assert!(bf.succeeded, "build should have succeeded");
    }

    // There should be at least one ProjectStarted and one ProjectFinished.
    let project_started_count = events
        .iter()
        .filter(|e| matches!(e, BinlogEvent::ProjectStarted(_)))
        .count();
    let project_finished_count = events
        .iter()
        .filter(|e| matches!(e, BinlogEvent::ProjectFinished(_)))
        .count();
    assert!(
        project_started_count >= 1,
        "expected at least 1 ProjectStarted, got {project_started_count}"
    );
    assert_eq!(
        project_started_count, project_finished_count,
        "ProjectStarted/Finished count mismatch"
    );

    // There should be at least one TargetStarted event.
    let target_started_count = events
        .iter()
        .filter(|e| matches!(e, BinlogEvent::TargetStarted(_)))
        .count();
    assert!(
        target_started_count >= 1,
        "expected at least 1 TargetStarted"
    );

    // String table should have been populated.
    assert!(
        !reader.strings().is_empty(),
        "string table should not be empty"
    );
}

#[test]
fn string_table_contains_project_path() {
    let file = File::open(HELLO_BINLOG).expect("missing test fixture: hello.binlog");
    let mut reader = BinlogReader::open(file).expect("failed to open binlog");
    let _ = reader.read_all_events().expect("failed to read events");

    // The string table should contain the project file name.
    let has_csproj = (0..reader.strings().len())
        .filter_map(|i| reader.strings().get(i as i32).ok().flatten())
        .any(|s: &str| s.contains("HelloBinlog.csproj"));
    assert!(has_csproj, "string table should contain the .csproj path");
}

#[test]
fn events_have_consistent_record_kinds() {
    let file = File::open(HELLO_BINLOG).expect("missing test fixture: hello.binlog");
    let mut reader = BinlogReader::open(file).expect("failed to open binlog");
    let events = reader.read_all_events().expect("failed to read events");

    // Verify that record_kind() returns the correct variant for every event.
    for event in &events {
        let kind = event.record_kind();
        // Round-trip: the kind discriminant must match the variant.
        match event {
            BinlogEvent::BuildStarted(_) => {
                assert_eq!(kind, munin::BinaryLogRecordKind::BuildStarted)
            }
            BinlogEvent::BuildFinished(_) => {
                assert_eq!(kind, munin::BinaryLogRecordKind::BuildFinished)
            }
            BinlogEvent::ProjectStarted(_) => {
                assert_eq!(kind, munin::BinaryLogRecordKind::ProjectStarted)
            }
            BinlogEvent::ProjectFinished(_) => {
                assert_eq!(kind, munin::BinaryLogRecordKind::ProjectFinished)
            }
            _ => {
                // For the remaining variants, just verify record_kind()
                // doesn't panic and returns a non-zero value.
                let _ = kind;
            }
        }
    }
}

#[test]
fn next_event_by_event_matches_read_all() {
    // Read events one at a time and compare with read_all_events.
    let file1 = File::open(HELLO_BINLOG).expect("missing test fixture");
    let mut reader1 = BinlogReader::open(file1).expect("failed to open binlog");
    let all_events = reader1.read_all_events().expect("read_all failed");

    let file2 = File::open(HELLO_BINLOG).expect("missing test fixture");
    let mut reader2 = BinlogReader::open(file2).expect("failed to open binlog");

    let mut count = 0;
    while let Some(event) = reader2.next_event().expect("next_event failed") {
        assert_eq!(
            event.record_kind(),
            all_events[count].record_kind(),
            "event {} record kind mismatch",
            count
        );
        count += 1;
    }
    assert_eq!(count, all_events.len(), "event count mismatch");
}

#[test]
fn nvl_table_populated_from_real_binlog() {
    let file = File::open(HELLO_BINLOG).expect("missing test fixture");
    let mut reader = BinlogReader::open(file).expect("failed to open binlog");
    let _ = reader.read_all_events().expect("read_all failed");

    // A real build usually has name-value lists (global/project properties).
    // The NVL table should have at least one entry.
    assert!(
        !reader.nvl_table().is_empty(),
        "NVL table should not be empty for a real build"
    );
}

#[test]
fn extract_archives_does_not_error() {
    let file = File::open(HELLO_BINLOG).expect("missing test fixture");
    let mut reader = BinlogReader::open(file).expect("failed to open binlog");
    let _ = reader.read_all_events().expect("read_all failed");

    // extract_archives should not error even if there are no archives.
    let entries = reader.extract_archives().expect("extract_archives failed");

    // If there are archives, every entry should have a non-empty path.
    for entry in &entries {
        assert!(
            !entry.path.is_empty(),
            "archive entry path should not be empty"
        );
    }
}

#[test]
fn build_started_has_nonempty_environment() {
    let file = File::open(HELLO_BINLOG).expect("missing test fixture");
    let mut reader = BinlogReader::open(file).expect("failed to open binlog");
    let events = reader.read_all_events().expect("read_all failed");

    let bs = events
        .iter()
        .find_map(|e| match e {
            BinlogEvent::BuildStarted(bs) => Some(bs),
            _ => None,
        })
        .expect("no BuildStarted event found");

    let env = bs.environment.as_ref().expect("environment should be Some");
    assert!(
        !env.is_empty(),
        "BuildStarted.environment should not be empty"
    );
}

